// Transform key-value rows into a config object
const config = {};
for (const item of $input.all()) {
  config[item.json.Key] = item.json.Value;
}

// Parse job titles
const jobTitles = (config.job_titles || 'Product Designer').split(',').map(t => t.trim());
const scoreThreshold = parseFloat(config.score_threshold || '4.0');
const scanBudget = parseInt(config.scan_budget_daily || '200');

return [{ json: { config, jobTitles, scoreThreshold, scanBudget } }];

const results = [];
const inputItem = $input.first().json;
const searchTitle = (inputItem.search_parameters && inputItem.search_parameters.q) || 'unknown';

// Handle errors or empty results
if (inputItem.error || !inputItem.jobs_results || inputItem.jobs_results.length === 0) {
  return [{ json: { results: [], title: searchTitle, error: inputItem.error || 'No results' } }];
}

for (const job of inputItem.jobs_results) {
  const primaryLink = (job.apply_options && job.apply_options[0] && job.apply_options[0].link) || '';
  let domain = '';
  try { domain = primaryLink ? new URL(primaryLink).hostname.replace('www.', '') : ''; } catch(e) {}
  const source = (job.apply_options && job.apply_options[0] && job.apply_options[0].title) || 'Google Jobs';

  // Parse freshness from detected_extensions.posted_at
  let freshnessHours = 24;
  const postedAt = (job.detected_extensions && job.detected_extensions.posted_at) || '';
  if (postedAt.includes('hour')) {
    freshnessHours = parseInt(postedAt) || 12;
  } else if (postedAt.includes('day')) {
    freshnessHours = (parseInt(postedAt) || 1) * 24;
  } else if (postedAt.includes('just') || postedAt.includes('now') || postedAt.includes('moment')) {
    freshnessHours = 1;
  }

  const company = job.company_name || '';
  const title = job.title || '';
  const dedupKey = company.toLowerCase() + '|' + title.toLowerCase() + '|' + domain;

  results.push({
    id: 'serp_' + Date.now() + '_' + Math.random().toString(36).substring(2, 6),
    source: source,
    company: company,
    title: title,
    url: primaryLink,
    snippet: (job.description || '').substring(0, 500),
    dateFound: new Date().toISOString(),
    freshnessHours: freshnessHours,
    Status: 'New',
    'Dedup Key': dedupKey,
    Rendering: 'static'
  });
}

return results.map(r => ({ json: r }));

// Get existing dedup keys from the pipeline sheet
const existingKeys = new Set($("Read Pipeline for Dedup").all().map(i => i.json["Dedup Key"]).filter(Boolean));

// Get incoming jobs — works for both cron/SerpAPI path and email path
let incoming;
try {
  incoming = $("Parse Search Results").all();
} catch(e) {
  incoming = $("Normalize Email Jobs").all();
}

const newListings = incoming.filter(i => i.json["Dedup Key"] && !existingKeys.has(i.json["Dedup Key"]));

// Deduplicate within this batch (same job from multiple sources)
const seen = new Set();
const dedupedNew = newListings.filter(i => {
  if (seen.has(i.json["Dedup Key"])) return false;
  seen.add(i.json["Dedup Key"]);
  return true;
});

if (dedupedNew.length === 0) {
  return [{ json: { _nothingNew: true } }];
}

return dedupedNew;

const raw = $input.first().json.output || $input.first().json.text || '';
let parsed = { decision: 'MAYBE', reason: 'Could not parse response' };
try {
  const match = raw.match(/\{[\s\S]*?\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch(e) {
  parsed.reason = 'Parse error: ' + raw.substring(0, 100);
}

const sourceItem = $('Batch for Pre-Screen').item;
const newStatus = parsed.decision === 'REJECT' ? 'Pre-Rejected' : 'Pre-Screened';

return [{ json: { ...sourceItem.json, preScreenDecision: parsed.decision, preScreenReason: parsed.reason, status: newStatus } }];

const sourceItem = $('Filter Passed Pre-Screen').item;
const htmlResponse = $input.first().json;
let jdText = '';
let confidence = 'high';

if (htmlResponse.error || !htmlResponse) {
  // Fallback to snippet
  jdText = sourceItem.json.snippet || '';
  confidence = 'low';
} else {
  const html = typeof htmlResponse === 'string' ? htmlResponse : JSON.stringify(htmlResponse);
  // Strip HTML tags and collapse whitespace
  jdText = html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);

  // If content is very short, likely JS-rendered — fall back to snippet
  if (jdText.length < 200) {
    jdText = sourceItem.json.snippet || jdText;
    confidence = 'low';
  }
}

return [{ json: { ...sourceItem.json, jdText, confidence } }];

const raw = $input.first().json.output || $input.first().json.text || '{}';
const sourceItem = $('Extract JD Text').item;
let eval_data = {};

try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) eval_data = JSON.parse(match[0]);
} catch(e) {
  eval_data = { scores: {}, overall: 0, grade: 'F', summary: 'Parse error', confidence: 'low' };
}

const scores = eval_data.scores || {};

// Apply weights
const weights = { role_match: 0.20, skills: 0.20, seniority: 0.12, compensation: 0.10, geographic: 0.08, company_stage: 0.08, product_market: 0.07, growth: 0.07, interview_likelihood: 0.05, timeline: 0.03 };
const weightedScore = Object.keys(weights).reduce((sum, k) => sum + (scores[k] || 3) * weights[k], 0);

// Gate-pass logic
let finalScore = weightedScore;
let finalGrade = eval_data.grade || 'C';
if ((scores.role_match || 0) <= 1 || (scores.skills || 0) <= 1) {
  finalGrade = 'D';
  finalScore = Math.min(finalScore, 2.9);
}

// Freshness boost
const freshnessHours = eval_data.freshness_hours || 24;
let freshnessBoost = 0;
if (freshnessHours < 6) freshnessBoost = 0.3;
else if (freshnessHours < 24) freshnessBoost = 0.2;
const adjustedScore = Math.min(5, finalScore + freshnessBoost);

// Recalculate grade from adjusted score
if (finalGrade !== 'D' && finalGrade !== 'F') {
  if (adjustedScore >= 4.5) finalGrade = 'A';
  else if (adjustedScore >= 3.8) finalGrade = 'B';
  else if (adjustedScore >= 3.0) finalGrade = 'C';
  else if (adjustedScore >= 2.0) finalGrade = 'D';
  else finalGrade = 'F';
}

return [{ json: {
  ...sourceItem.json,
  eval: eval_data,
  scores,
  overall: parseFloat(weightedScore.toFixed(2)),
  grade: finalGrade,
  freshnessAdjustedScore: parseFloat(adjustedScore.toFixed(2)),
  status: 'Evaluated'
} }];

const raw = $input.first().json.output || $input.first().json.text || '{}';
const sourceItem = $('Score >= Threshold?').item;
let cvData = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) cvData = JSON.parse(match[0]);
} catch(e) { cvData = { title: 'Preston Bezant', summary: raw.substring(0, 200) }; }

// Build experience HTML
const expHtml = (cvData.experience || []).map(role => `
  <div class="role">
    <div class="role-header">
      <strong>${role.company}</strong> — ${role.role}
      <span class="dates">${role.dates} | ${role.location || ''}</span>
    </div>
    <ul>${(role.bullets || []).map(b => `<li>${b}</li>`).join('')}</ul>
  </div>`).join('');

// Build skills HTML  
const skills = cvData.skills || {};
const skillsHtml = [
  skills.design?.length ? `<div class="skill-group"><strong>Design:</strong> ${skills.design.join(', ')}</div>` : '',
  skills.technical?.length ? `<div class="skill-group"><strong>Technical:</strong> ${skills.technical.join(', ')}</div>` : '',
  skills.tools?.length ? `<div class="skill-group"><strong>Tools:</strong> ${skills.tools.join(', ')}</div>` : ''
].filter(Boolean).join('');

const contact = cvData.contact || {};

const cvHtml = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>${cvData.title || 'Preston Bezant'} — CV</title><style>body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:800px;margin:0 auto;padding:40px 24px;color:#1a1a1a;line-height:1.5;font-size:14px}h1{font-size:24px;margin-bottom:4px}h2{font-size:16px;border-bottom:1px solid #ddd;padding-bottom:4px;margin-top:24px;margin-bottom:12px}h3{font-size:14px;margin-bottom:2px}.contact{color:#555;margin-bottom:24px;font-size:13px}.role{margin-bottom:16px}.role-header{display:flex;justify-content:space-between;flex-wrap:wrap}.dates{color:#666;font-size:12px}ul{margin:6px 0;padding-left:20px}li{margin-bottom:4px}.skill-group{margin-bottom:6px}</style></head><body><h1>${contact.name || 'Preston Bezant'}</h1><div class="title-line">${cvData.title || ''}</div><div class="contact">${contact.email || ''} | ${contact.phone || ''} | ${contact.portfolio || ''} | ${contact.location || ''}</div><h2>Summary</h2><p>${cvData.summary || ''}</p><h2>Experience</h2>${expHtml}<h2>Skills</h2>${skillsHtml}<h2>Education</h2>${(cvData.education || []).map(e => `<div><strong>${e.degree}</strong> — ${e.school} (${e.dates})</div>`).join('')}</body></html>`;

return [{ json: { ...sourceItem.json, cvData, cvHtml, cvVersion: 1 } }];

// Parse cover letter from the Cover Letter Agent output
const clRaw = $('Cover Letter AI Agent').item.json.output || '';
const prepRaw = $input.first().json.output || '{}';

let coverLetter = {};
try { const m = clRaw.match(/\{[\s\S]*\}/); if(m) coverLetter = JSON.parse(m[0]); } catch(e) {}

let prepAnswers = {};
try { const m = prepRaw.match(/\{[\s\S]*\}/); if(m) prepAnswers = JSON.parse(m[0]); } catch(e) {}

// Build cover letter HTML
const clHtml = `<div style="font-family:sans-serif;max-width:700px;margin:0 auto;padding:40px 24px;">
  <p>${new Date().toLocaleDateString('en-US', {year:'numeric',month:'long',day:'numeric'})}</p>
  <p>${coverLetter.salutation || 'Hi Hiring Team,'}</p>
  <p>${coverLetter.paragraph_1 || ''}</p>
  <p>${coverLetter.paragraph_2 || ''}</p>
  <p>${coverLetter.paragraph_3 || ''}</p>
  <p style="white-space:pre-line">${coverLetter.closing || 'Best,\nPreston Bezant'}</p>
</div>`;

const sourceItem = $('Inject CV Template').item;
return [{ json: { ...sourceItem.json, coverLetter, clHtml, prepAnswers } }];

// Cleanup logic runs via separate sheet operations
// This logs the completion
const now = new Date();
return [{ json: { completedAt: now.toISOString(), message: 'Pipeline run complete. Check sheet for results.' } }];

const item = $input.first().json;
const company = (item.company||'unknown').replace(/[^a-z0-9]/gi,'-').toLowerCase().substring(0,30);
const title   = (item.title||'role').replace(/[^a-z0-9]/gi,'-').toLowerCase().substring(0,40);
const date    = new Date().toISOString().split('T')[0];
return [{ json: {
  ...item,
  cvFilename:  date + '-' + company + '-' + title + '-CV.html',
  clFilename:  date + '-' + company + '-' + title + '-CoverLetter.html',
  folderId: '1OiKZtIMRe8XRdGPj9jJb0K3I5Wd3Xn37'
} }];

const src   = $('Prepare Drive Upload').item.json;
const cvId  = $('Upload CV Content').item.json.id || '';
const clId  = $input.first().json.id || '';  // CL is current input (last in chain)
const cvPath = cvId ? `https://drive.google.com/file/d/${cvId}/view` : '(cv upload failed)';
const clPath = clId ? `https://drive.google.com/file/d/${clId}/view` : '(cl upload failed)';
return [{ json: { ...src, cvPath, clPath } }];

const j = $('Build Drive Links').item.json;
const sheetUrl = 'https://docs.google.com/spreadsheets/d/1FyCBvmiLjX_0oj9GuKGYfUHUox3foC9TZnPEfNyEjsg';

const grade  = j.grade || '?';
const score  = j.freshnessAdjustedScore !== undefined ? j.freshnessAdjustedScore.toFixed(2) : (j.overallScore || '?');
const cvLink  = j.cvPath  ? `[📄 CV](${j.cvPath})`           : '_(no CV)_';
const clLink  = j.clPath  ? `[✉️ Cover Letter](${j.clPath})` : '_(no CL)_';
const jobLink = j.url     ? `[🔗 Job Posting](${j.url})`     : '';

const msg = [
  `✅ **${j.title}** at **${j.company}**`,
  `> Grade: **${grade}** | Score: **${score}** | ${j.location || ''}`,
  `> ${cvLink}  •  ${clLink}  ${jobLink ? '•  ' + jobLink : ''}`,
  `> [View Spreadsheet](${sheetUrl})`
].join('\n');

return [{ json: { ...j, discordMessage: msg } }];

// Only process listings from the last 48 hours, max 50 per run
const cutoff = new Date(Date.now() - 48 * 60 * 60 * 1000);
const recent = $input.all().filter(item => {
  const d = new Date(item.json.dateFound || item.json.DateFound || 0);
  return d >= cutoff;
}).slice(0, 50);
if (recent.length === 0) return [{ json: { _skip: true } }];
return recent;

// ============================================================
// EMAIL PARSER — handles Gmail Trigger single-email output shape.
// Returns a flat array of JobAlert objects.
// Supports: LinkedIn, Indeed, Glassdoor, ZipRecruiter, Dice, Jobright,
//           Google Job Alerts, and generic fallback.
//
// Adding a new email source:
//   1. Write parseYourSource(html, subject, emailDate) → JobAlert[]
//   2. Add an entry to SOURCE_REGISTRY (before the 'generic' entry)
// ============================================================
const emails = $input.all();
const jobs = [];

// ---- Utility functions ----

const decodeBase64 = (data) => {
  if (!data || typeof data !== 'string') return '';
  try {
    const normalized = data.replace(/-/g, '+').replace(/_/g, '/');
    return Buffer.from(normalized, 'base64').toString('utf-8');
  } catch {
    return '';
  }
};

const decodeMimeWords = (value = '') => {
  if (!value || typeof value !== 'string') return '';
  // RFC 2047 sec 6.2: collapse whitespace between adjacent encoded-words
  const collapsed = value.replace(/\?=\s+=\?/g, '?==?');
  return collapsed.replace(/=\?([^?]+)\?([BQbq])\?([^?]+)\?=/g, (_, charset, enc, text) => {
    try {
      if ((enc || '').toUpperCase() === 'B') {
        return Buffer.from(text, 'base64').toString('utf-8');
      }
      // Q-encoding: collect raw bytes and decode as UTF-8 via Buffer
      const bytes = [];
      for (let i = 0; i < text.length; ) {
        if (text[i] === '=' && i + 2 < text.length && /[0-9A-Fa-f]{2}/.test(text.substring(i+1, i+3))) {
          bytes.push(parseInt(text.substring(i+1, i+3), 16));
          i += 3;
        } else if (text[i] === '_') {
          bytes.push(0x20);
          i++;
        } else {
          bytes.push(text.charCodeAt(i));
          i++;
        }
      }
      return Buffer.from(bytes).toString('utf-8');
    } catch {
      return text;
    }
  });
};

const decodeTrackedUrl = (u = '') => {
  try {
    const parsed = new URL(u);
    const keys = ['url', 'u', 'target', 'dest', 'destination', 'redirect', 'redirectUrl'];
    for (const key of keys) {
      const val = parsed.searchParams.get(key);
      if (val && /^https?:\/\//i.test(val)) return val;
    }
    return u;
  } catch {
    return u;
  }
};

const isLikelyJobUrl = (u = '') => {
  if (!/^https?:\/\//i.test(u)) return false;
  if (/(\.png|\.jpg|\.jpeg|\.gif|\.svg|\.webp|apps\.apple\.com|play\.google\.com|unsubscribe|privacy|terms|dashboard|settings)/i.test(u)) return false;
  // Accept Google notification redirects (resolved to real URL downstream)
  if (/notifications\.googleapis\.com\/email\/redirect/i.test(u)) return true;
  return /(linkedin\.com\/(comm\/)?jobs\/(view|search)|indeed\.com|glassdoor\.com|ziprecruiter\.com|dice\.com|jobright\.ai|greenhouse\.io|lever\.co|workdayjobs|job|career|position|vacanc|opportunit|apply)/i.test(u);
};

const parseLinkedInSubject = (subject = '') => {
  const cleaned = decodeMimeWords(subject || '').replace(/[\u201c\u201d]/g, '"').trim();
  // Digest format: "search term": Company - Job Title and more
  const digestMatch = cleaned.match(/^["']?[^:"']+["']?\s*:\s*([^\n-]{2,120})\s*-\s*([^\n]{2,160}?)(?:\s+and more.*)?$/i);
  if (digestMatch) {
    return { jobTitle: digestMatch[2].trim(), company: digestMatch[1].trim() };
  }
  // Job alert format: "Your job alert for product design engineer"
  const alertMatch = cleaned.match(/(?:Your\s+)?job\s+alert\s+for\s+(.+)/i);
  if (alertMatch) {
    return { jobTitle: alertMatch[1].trim(), company: '' };
  }
  const basic = cleaned.replace(/^(re:|fwd:|new jobs?|job alert|job recommendations?|career update)[:\s-]*/gi, '').trim();
  return { jobTitle: basic || 'Unknown Position', company: '' };
};

// Parse "Subject at Company" patterns (Dice IntelliSearch, Jobright, etc.)
const parseSubjectAtCompany = (subject = '') => {
  const cleaned = decodeMimeWords(subject || '').replace(/[\u201c\u201d]/g, '"').trim();
  // Dice: "Your IntelliSearch Alert: Title at Company"
  const intelliMatch = cleaned.match(/IntelliSearch Alert[:\s]*\s*(.+?)\s+at\s+(.+?)\.?\s*$/i);
  if (intelliMatch) return { jobTitle: intelliMatch[1].trim(), company: intelliMatch[2].trim() };
  // Jobright: 'Your job matches for "Title" — curated for you from Jobright'
  const jobrightMatch = cleaned.match(/job matches for\s+["\u201c]([^"\u201d]+)["\u201d]/i);
  if (jobrightMatch) return { jobTitle: jobrightMatch[1].trim(), company: '' };
  // Generic "Title at Company" pattern
  const atMatch = cleaned.match(/^(.{5,80})\s+at\s+(.{2,80})$/i);
  if (atMatch) return { jobTitle: atMatch[1].trim(), company: atMatch[2].trim() };
  return null;
};

// ---- Source Registry ----
// To add a new email source:
//   1. Write a parseXxx(html, subject, emailDate) function below
//   2. Add an entry here BEFORE the 'generic' catch-all entry
//   detect(from, subject, content) should return true when this source matches
const SOURCE_REGISTRY = [
  {
    name: 'google_alerts',
    detect: (from) => /notify-noreply@google\.com/i.test(from) || /job\s*alerts?\s*from\s*google/i.test(from),
    parse: (html, subject, emailDate) => parseGoogleAlerts(html, subject, emailDate)
  },
  {
    name: 'linkedin',
    detect: (from, subject, content) =>
      /linkedin/i.test(from) ||
      (!from && /(linkedin\.com\/(comm\/)?jobs\/view|jobalerts-noreply@linkedin\.com)/i.test(content)),
    parse: (html, subject, emailDate) => parseLinkedIn(html, subject, emailDate)
  },
  {
    name: 'indeed',
    detect: (from) => /indeed/i.test(from),
    parse: (html, subject, emailDate) => parseIndeed(html || '', subject, emailDate)
  },
  {
    name: 'glassdoor',
    detect: (from) => /glassdoor/i.test(from),
    parse: (html, subject, emailDate) => parseGlassdoor(html || '', subject, emailDate)
  },
  {
    name: 'ziprecruiter',
    detect: (from) => /ziprecruiter/i.test(from),
    parse: (html, subject, emailDate) => parseZipRecruiter(html || '', subject, emailDate)
  },
  {
    name: 'dice',
    detect: (from, subject) => /dice/i.test(from) || /IntelliSearch Alert/i.test(subject),
    parse: (html, subject, emailDate) => parseDice(html || '', subject, emailDate)
  },
  {
    name: 'jobright',
    detect: (from) => /jobright/i.test(from),
    parse: (html, subject, emailDate) => parseJobright(html || '', subject, emailDate)
  },
  {
    name: 'generic',
    detect: () => true,
    parse: (html, subject, emailDate) => parseGeneric(html || '', subject, emailDate)
  }
];

// ---- Main email loop ----

for (const email of emails) {
  const raw = email.json || {};
  let html = '', text = '', subject = '', from = '', emailDate = new Date().toISOString(), emailId = '';

  const payload = raw.payload || {};
  const getHeader = (name) => {
    const target = (name || '').toLowerCase();
    const headers = Array.isArray(payload.headers) ? payload.headers : [];
    const hit = headers.find(h => (h?.name || '').toLowerCase() === target);
    if (hit?.value) return hit.value;

    const lower = (name || '').toLowerCase();
    const title = lower ? `${lower.charAt(0).toUpperCase()}${lower.slice(1)}` : name;
    const variants = [name, lower, title, (name || '').toUpperCase()];
    for (const key of variants) {
      if (!key) continue;
      const v = raw[key];
      if (typeof v === 'string' && v.trim()) return v;
    }
    return '';
  };

  const walkParts = (parts, acc = { text: '', html: '' }) => {
    if (!Array.isArray(parts)) return acc;
    for (const part of parts) {
      const mime = (part?.mimeType || '').toLowerCase();
      const data = part?.body?.data;
      if (mime === 'text/plain' && !acc.text && data) acc.text = decodeBase64(data);
      if (mime === 'text/html' && !acc.html && data) acc.html = decodeBase64(data);
      if (Array.isArray(part?.parts)) walkParts(part.parts, acc);
      if (acc.text && acc.html) break;
    }
    return acc;
  };

  subject = decodeMimeWords(getHeader('Subject') || raw.subject || '');
  from = decodeMimeWords(getHeader('From') || raw.from?.value?.[0]?.address || raw.from || '');

  if (raw.payload) {
    emailDate = raw.internalDate ? new Date(parseInt(raw.internalDate)).toISOString() : (raw.date || new Date().toISOString());
    emailId = raw.id || '';

    const bodyData = raw.payload?.body?.data;
    if (bodyData) {
      const decoded = decodeBase64(bodyData);
      const mime = (raw.payload?.mimeType || '').toLowerCase();
      if (mime === 'text/plain') text = decoded;
      else html = decoded;
    }

    const walked = walkParts(raw.payload?.parts || []);
    if (!text && walked.text) text = walked.text;
    if (!html && walked.html) html = walked.html;

    if (!text && !html) {
      text = raw.text || '';
      html = raw.html || raw.snippet || '';
    } else {
      text = text || raw.text || '';
      html = html || raw.html || raw.snippet || '';
    }
  } else {
    html = raw.html || '';
    text = raw.text || '';
    emailDate = raw.date || new Date().toISOString();
    emailId = raw.id || '';
    if (!text && !html) html = raw.snippet || '';
  }

  if (!text && !html) {
    text = raw.text || '';
    html = raw.html || raw.snippet || '';
  }

  const contentForSource = `${subject}\n${from}\n${text}\n${html}`;

  // Detect source using registry — first match wins, 'generic' is always last
  let source = 'generic';
  let registryEntry = SOURCE_REGISTRY[SOURCE_REGISTRY.length - 1];
  for (const entry of SOURCE_REGISTRY) {
    if (entry.detect(from, subject, contentForSource)) {
      source = entry.name;
      registryEntry = entry;
      break;
    }
  }

  let extracted = [];
  try {
    extracted = registryEntry.parse(html || text, subject, emailDate);
  } catch (e) {
    extracted = parseGeneric(html || text, subject, emailDate);
  }

  for (const job of extracted) {
    if (job.jobTitle) jobs.push({ ...job, source, emailDate, emailId, parseConfidence: job.parseConfidence || 'regex' });
  }
}

// ---- Source-specific parsers ----

function parseGoogleAlerts(html, subject, emailDate) {
  const jobs = [];
  const seen = new Set();

  // Decode quoted-printable: soft line breaks + hex sequences + entities
  const normalized = (html || '')
    .replace(/=\r?\n/g, '')
    .replace(/=([0-9A-Fa-f]{2})/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&amp;/gi, '&');

  // Extract search query from subject: '6 new jobs for "creative technologist jobs" - Mar 5'
  const subjectMatch = subject.match(/(?:\d+\s+new\s+)?jobs?\s+for\s+["\u201c]([^"\u201d]+)["\u201d]/i);
  const searchQuery = subjectMatch ? subjectMatch[1].trim() : '';

  // Location hint from the email header (e.g., "Near Kyle, TX")
  const locationHintMatch = normalized.match(/Near\s+([^<]{3,60})<\/span>/i);
  const locationHint = locationHintMatch ? locationHintMatch[1].trim() : '';

  // Each job card is an <a> wrapping a table with title/company/location.
  // The footer "Explore jobs" / "Manage Alerts" / "Unsubscribe" links are filtered out.
  const cardRegex = /<a[^>]+href=["'](https:\/\/notifications\.googleapis\.com\/email\/redirect[^"'< ]+)["'][^>]*>([\s\S]*?)<\/a>/gi;
  let cardMatch;
  while ((cardMatch = cardRegex.exec(normalized)) !== null) {
    const href = (cardMatch[1] || '').trim();
    const cardHtml = cardMatch[2] || '';

    // Skip footer/utility links
    if (/Explore\s+jobs|Manage\s+Alerts|Unsubscribe|Forward\s+icon|google_logo/i.test(cardHtml)) continue;

    // Job title: <span style="...font-size: 16px; line-height: 1.43em;">Title</span>
    const titleMatch = cardHtml.match(/<span[^>]*font-size:\s*16px[^>]*>([^<]+)<\/span>/i);
    const jobTitle = titleMatch ? titleMatch[1].trim() : '';
    if (!jobTitle) continue; // Not a job card

    // Company: <div style="color: black; font-size: 14px; ...">Company Name</div>
    const companyMatch = cardHtml.match(/<div[^>]*color:\s*(?:#000000|black)[^>]*>([^<]+)<\/div>/i);
    const company = companyMatch ? companyMatch[1].trim() : '';

    // Location: first <span> child inside a color:#8A8A8A div that doesn't start with "via "
    const locationDivs = [...cardHtml.matchAll(/<div[^>]*color:\s*#8A8A8A[^>]*>([\s\S]*?)<\/div>/gi)];
    let location = '';
    for (const div of locationDivs) {
      const spanMatch = div[1].match(/<span[^>]*>([^<]+)<\/span>/i);
      if (spanMatch && !/^via\s/i.test(spanMatch[1].trim())) {
        location = spanMatch[1].trim();
        break;
      }
    }

    // Employment type from the Work icon span (Full-time, Part-time, etc.)
    const typeMatch = cardHtml.match(/work_grey600[^>]*>[^<]*<\/img>\s*<span[^>]*>([^<]+)<\/span>/i)
      || cardHtml.match(/<span[^>]*>(\bFull-time\b|\bPart-time\b|\bContract\b|\bTemporary\b|\bInternship\b)[^<]*<\/span>/i);
    const employmentType = typeMatch ? typeMatch[1].trim() : '';

    if (seen.has(href)) continue;
    seen.add(href);

    jobs.push({
      jobTitle,
      company,
      location: location || locationHint,
      description: [
        searchQuery ? `Google Alert: ${searchQuery}` : '',
        employmentType || ''
      ].filter(Boolean).join(' — ') || '',
      applyUrl: href,
      parseConfidence: 'high',
      needsRedirectResolution: true
    });
  }

  return jobs.length ? jobs : parseGeneric(html, subject, emailDate);
}

function parseLinkedIn(content, subject, emailDate) {
  const jobs = [];
  const seen = new Set();
  const normalized = (content || '').replace(/=\r?\n/g, '').replace(/=3D/gi, '=').replace(/&amp;/gi, '&');
  const subjectFallback = parseLinkedInSubject(subject);

  // ---- PASS 1: Line-by-line digest parser ----
  const lines = normalized.split('\n').map(l => l.trimEnd());

  for (let i = 0; i < lines.length; i++) {
    const viewJobMatch = lines[i].match(/^\s*View job:\s*(https?:\/\/(?:www\.)?linkedin\.com\/(?:comm\/)?jobs\/view\/[^\s]+)/i);
    if (!viewJobMatch) continue;

    const applyUrl = decodeTrackedUrl(viewJobMatch[1].trim()).replace(/[),.;]+$/g, '');
    if (!applyUrl || seen.has(applyUrl)) continue;
    seen.add(applyUrl);

    const contentLines = [];
    let backIdx = i - 1;
    let scanned = 0;

    while (backIdx >= 0 && contentLines.length < 5 && scanned < 10) {
      const line = lines[backIdx].trim();
      backIdx--;
      scanned++;

      if (/^-{3,}$/.test(line)) break;
      if (/^Your job alert/i.test(line)) break;
      if (/^New jobs match/i.test(line)) break;

      if (!line) continue;
      if (/^(Apply with|This company|Actively hiring|Be an early|Easy Apply)/i.test(line)) continue;

      contentLines.unshift(line);
    }

    let title = '', company = '', location = '';
    if (contentLines.length >= 3) {
      title = contentLines[0];
      company = contentLines[1];
      location = contentLines[2];
    } else if (contentLines.length === 2) {
      title = contentLines[0];
      company = contentLines[1];
    } else if (contentLines.length === 1) {
      title = contentLines[0];
    }

    jobs.push({
      jobTitle: title || subjectFallback.jobTitle || 'Unknown Position',
      company: company || subjectFallback.company || '',
      location: location || '',
      description: '',
      applyUrl,
      parseConfidence: title ? 'digest' : 'url_only'
    });
  }

  // ---- PASS 2: URL-only fallback ----
  const urlRegex = /https?:\/\/www\.linkedin\.com\/(?:comm\/)?jobs\/view\/[^\s<>"')\]]+/gi;
  const urlMatches = normalized.match(urlRegex) || [];
  for (const rawUrl of urlMatches) {
    const applyUrl = decodeTrackedUrl((rawUrl || '').trim()).replace(/[),.;]+$/g, '');
    if (!applyUrl || seen.has(applyUrl)) continue;
    seen.add(applyUrl);
    jobs.push({
      jobTitle: subjectFallback.jobTitle || 'Unknown Position',
      company: subjectFallback.company || '',
      location: '',
      description: '',
      applyUrl,
      parseConfidence: 'url_only'
    });
  }

  if (jobs.length) return jobs;

  // ---- PASS 3: HTML card fallback ----
  let m;
  const jobCardRegex = /<a[^>]+href="(https:\/\/(?:www\.)?linkedin\.com\/(?:comm\/)?jobs\/view\/[^"?]+)[^"]*"[^>]*>\s*([^<]{5,120})\s*<\/a>/gi;
  const companyRegex = /<span[^>]*class="[^"]*company[^"]*"[^>]*>([^<]+)<\/span>/gi;
  const urls = [], titles = [], companies = [];

  while ((m = jobCardRegex.exec(normalized)) !== null) {
    urls.push(decodeTrackedUrl(m[1] || ''));
    titles.push((m[2] || '').trim());
  }
  while ((m = companyRegex.exec(normalized)) !== null) {
    companies.push((m[1] || '').trim());
  }

  for (let i = 0; i < titles.length; i++) {
    const applyUrl = (urls[i] || '').trim();
    if (!applyUrl || seen.has(applyUrl)) continue;
    seen.add(applyUrl);
    jobs.push({
      jobTitle: titles[i] || subjectFallback.jobTitle || 'Unknown Position',
      company: companies[i] || subjectFallback.company || '',
      description: '',
      applyUrl,
      location: ''
    });
  }

  return jobs.length ? jobs : parseGeneric(normalized, subject, emailDate);
}

function parseDice(html, subject, emailDate) {
  const jobs = [];
  const seen = new Set();
  const subjectParsed = parseSubjectAtCompany(subject) || { jobTitle: subject.trim(), company: '' };

  // Dice IntelliSearch emails are single-job alerts — only need the first real dice.com URL
  const hrefRegex = /href=["']([^"']+)["']/gi;
  let m;
  while ((m = hrefRegex.exec(html)) !== null) {
    let url = (m[1] || '').trim();
    if (url.startsWith('/')) continue;
    url = decodeTrackedUrl(url);
    if (!/dice\.com/i.test(url)) continue;
    if (/unsubscribe|privacy|settings|preferences|manage|account/i.test(url)) continue;
    if (seen.has(url)) continue;
    seen.add(url);
    jobs.push({
      jobTitle: subjectParsed.jobTitle || 'Unknown Position',
      company: subjectParsed.company || '',
      description: '',
      applyUrl: url,
      location: '',
      parseConfidence: 'medium'
    });
    break; // Single-job alert — one URL is enough
  }

  if (jobs.length === 0) {
    const textUrlRegex = /https?:\/\/[^\s<>"')]+dice\.com[^\s<>"')]+/gi;
    const urls = (html.match(textUrlRegex) || []).map(decodeTrackedUrl);
    for (const url of urls) {
      if (/unsubscribe|privacy|settings|preferences|manage|account/i.test(url)) continue;
      if (seen.has(url)) continue;
      seen.add(url);
      jobs.push({
        jobTitle: subjectParsed.jobTitle || 'Unknown Position',
        company: subjectParsed.company || '',
        description: '',
        applyUrl: url,
        location: '',
        parseConfidence: 'low'
      });
      break;
    }
  }

  // Fallback: subject data with no URL is still a valid job hit
  if (jobs.length === 0 && subjectParsed.jobTitle && subjectParsed.jobTitle !== 'Unknown Position') {
    jobs.push({
      jobTitle: subjectParsed.jobTitle,
      company: subjectParsed.company || '',
      description: '',
      applyUrl: '',
      location: '',
      parseConfidence: 'subject_only'
    });
  }

  return jobs.length ? jobs : parseGeneric(html, subject, emailDate);
}

