function parseIndeed(html, subject, emailDate) {
  const jobs = [];
  const blockRegex = /href="(https:\/\/(?:www\.)?indeed\.com\/(?:viewjob|rc\/clk)[^"]+)"[\s\S]*?<h2[^>]*>([^<]+)<\/h2>[\s\S]*?<span[^>]*>([^<]+)<\/span>/gi;
  let m;
  while ((m = blockRegex.exec(html)) !== null)
    jobs.push({ jobTitle: m[2].trim(), company: m[3].trim(), description: '', applyUrl: m[1], location: '' });
  if (jobs.length === 0) {
    const linkRegex = /href="(https:\/\/(?:www\.)?indeed\.com\/[^"]+)"[^>]*>([^<]{5,80})<\/a>/gi;
    while ((m = linkRegex.exec(html)) !== null)
      if (!m[2].includes('Indeed') && !m[2].includes('Unsubscribe'))
        jobs.push({ jobTitle: m[2].trim(), company: '', description: '', applyUrl: m[1], location: '' });
  }
  return jobs.length ? jobs : parseGeneric(html, subject, emailDate);
}

function parseGlassdoor(html, subject, emailDate) {
  const jobs = [];
  const blockRegex = /href="(https:\/\/(?:www\.)?glassdoor\.com\/[^"]+job[^"]+)"[^>]*>([^<]{5,100})<\/a>/gi;
