function parseGeneric(html, subject, emailDate) {
  const jobs = [];
  const seen = new Set();
  // Try specific subject patterns first, then LinkedIn-style fallback
  const subjectParsed = parseSubjectAtCompany(subject) || parseLinkedInSubject(subject);

  const hrefRegex = /href=["']([^"']+)["']/gi;
  let m;
  while ((m = hrefRegex.exec(html)) !== null) {
    let url = (m[1] || '').trim();
    if (url.startsWith('/')) continue;
    url = decodeTrackedUrl(url);
    if (!isLikelyJobUrl(url) || seen.has(url)) continue;
    seen.add(url);
    jobs.push({
      jobTitle: subjectParsed.jobTitle || 'Unknown Position',
      company: subjectParsed.company || '',
      description: '',
      applyUrl: url,
      location: '',
      parseConfidence: 'medium'
    });
  }

  if (jobs.length === 0) {
    const textUrlRegex = /https?:\/\/[^\s<>"')]+/gi;
    const urls = (html.match(textUrlRegex) || []).map(decodeTrackedUrl);
    for (const url of urls) {
      if (!isLikelyJobUrl(url) || seen.has(url)) continue;
      seen.add(url);
      jobs.push({
        jobTitle: subjectParsed.jobTitle || 'Unknown Position',
        company: subjectParsed.company || '',
        description: '',
        applyUrl: url,
        location: '',
        parseConfidence: 'low'
      });
    }
  }

  if (jobs.length === 0)
    jobs.push({
      jobTitle: subjectParsed.jobTitle || subject.trim() || 'Unknown Position',
      company: subjectParsed.company || '',
      description: '',
      applyUrl: '',
      location: '',
      parseConfidence: 'very_low'
    });

  return jobs;
}

