function parseIndeed(html, subject, emailDate) {
  const jobs = [];
  const blockRegex = /href="(https:\/\/(?:www\.)?indeed\.com\/(?:viewjob|rc\/clk)[^"]+)"[\s\S]*?<h2[^>]*>([^<]+)<\/h2>[\s\S]*?<span[^>]*>([^<]+)<\/span>/gi;
  let m;
  while ((m = blockRegex.exec(html)) !== null)
    jobs.push({ jobTitle: m[2].trim(), company: m[3].trim(), description: '', applyUrl: m[1], location: '' });
  if (jobs.length === 0) {
    const linkRegex = /href="(https:\/\/(?:www\.)?indeed\.com\/[^"]+)"[^>]*>([^<]{5,80})<\/a>/gi;
    while ((m = linkRegex.exec(html)) !== null)
      if (!m[2].includes('Indeed') && !m[2].includes('Unsubscribe'))
        jobs.push({ jobTitle: m[2].trim(), company: '', description: '', applyUrl: m[1], location: '' });
  }
  return jobs.length ? jobs : parseGeneric(html, subject, emailDate);
}

function parseGlassdoor(html, subject, emailDate) {
  const jobs = [];
  const blockRegex = /href="(https:\/\/(?:www\.)?glassdoor\.com\/[^"]+job[^"]+)"[^>]*>([^<]{5,100})<\/a>/gi;
  let m;
  while ((m = blockRegex.exec(html)) !== null)
    if (!m[2].includes('Glassdoor') && !m[2].includes('Unsubscribe'))
      jobs.push({ jobTitle: m[2].replace(/<[^>]+>/g, '').trim(), company: '', description: '', applyUrl: m[1], location: '' });
  return jobs.length ? jobs : parseGeneric(html, subject, emailDate);
}

function parseZipRecruiter(html, subject, emailDate) {
  const jobs = [];
  const blockRegex = /href="(https:\/\/(?:www\.)?ziprecruiter\.com\/[^"]+)"[^>]*>([^<]{5,100})<\/a>/gi;
  let m;
  while ((m = blockRegex.exec(html)) !== null) {
    const text = m[2].trim();
    if (text && !text.includes('ZipRecruiter') && !text.includes('Unsubscribe') && text.length < 120)
      jobs.push({ jobTitle: text, company: '', description: '', applyUrl: m[1], location: '' });
  }
  return jobs.length ? jobs : parseGeneric(html, subject, emailDate);
}

function parseGeneric(html, subject, emailDate) {
  const jobs = [];
  const seen = new Set();
  // Try specific subject patterns first, then LinkedIn-style fallback
  const subjectParsed = parseSubjectAtCompany(subject) || parseLinkedInSubject(subject);

  const hrefRegex = /href=["']([^"']+)["']/gi;
  let m;
  while ((m = hrefRegex.exec(html)) !== null) {
    let url = (m[1] || '').trim();
    if (url.startsWith('/')) continue;
    url = decodeTrackedUrl(url);
    if (!isLikelyJobUrl(url) || seen.has(url)) continue;
    seen.add(url);
    jobs.push({
      jobTitle: subjectParsed.jobTitle || 'Unknown Position',
      company: subjectParsed.company || '',
      description: '',
      applyUrl: url,
      location: '',
      parseConfidence: 'medium'
    });
  }

  if (jobs.length === 0) {
    const textUrlRegex = /https?:\/\/[^\s<>"')]+/gi;
    const urls = (html.match(textUrlRegex) || []).map(decodeTrackedUrl);
    for (const url of urls) {
      if (!isLikelyJobUrl(url) || seen.has(url)) continue;
      seen.add(url);
      jobs.push({
        jobTitle: subjectParsed.jobTitle || 'Unknown Position',
        company: subjectParsed.company || '',
        description: '',
        applyUrl: url,
        location: '',
        parseConfidence: 'low'
      });
    }
  }

  if (jobs.length === 0)
    jobs.push({
      jobTitle: subjectParsed.jobTitle || subject.trim() || 'Unknown Position',
      company: subjectParsed.company || '',
      description: '',
      applyUrl: '',
      location: '',
      parseConfidence: 'very_low'
    });

  return jobs;
}

if (jobs.length === 0) return [{ json: { _noJobs: true } }];
return jobs.map(j => ({ json: j }));

const items = $input.all();
